#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { loadRecipeRelations } = require('./recipe-relations');

const GENERATED_NOTICE = [
	'<!--',
	'This file is auto-generated by scripts/recipes/generate-recipe-docs.js.',
	'Do not edit manually.',
	'-->',
	'',
].join('\n');

function parseArgs() {
	const args = {};

	process.argv.slice(2).forEach((arg) => {
		const [rawKey, ...valueParts] = arg.replace(/^--/, '').split('=');
		const value = valueParts.join('=');
		args[rawKey] = value === '' ? true : value;
	});

	return args;
}

function readJson(filePath) {
	if (!fs.existsSync(filePath)) {
		throw new Error(`File not found: ${filePath}`);
	}

	return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function ensureDir(dirPath) {
	if (!fs.existsSync(dirPath)) {
		fs.mkdirSync(dirPath, { recursive: true });
	}
}

function renderRecipesIndex(recipes) {
	const grouped = recipes.reduce((acc, recipe) => {
		const group = recipe.group || 'Uncategorized';
		if (!acc[group]) {
			acc[group] = [];
		}
		acc[group].push(recipe);
		return acc;
	}, {});

	const orderedGroups = Object.keys(grouped).sort((a, b) => {
		if (a === 'Uncategorized') {
			return 1;
		}
		if (b === 'Uncategorized') {
			return -1;
		}
		return a.localeCompare(b);
	});

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push('title: Recipes');
	lines.push('---');
	lines.push('');
	lines.push('# Recipes');
	lines.push('');
	lines.push(
		'Recipes are practical examples that show how to customize WPGraphQL. Related actions, filters, and functions are inferred from recipe markdown (mentions of known hook and function names from `docs/generated/hooks-index.json` and `docs/generated/functions-index.json`), merged with any explicit `relatedActions` / `relatedFilters` / `relatedFunctions` lists in frontmatter.'
	);
	lines.push('');

	if (orderedGroups.length === 0) {
		lines.push('No markdown recipes have been migrated yet.');
		lines.push('');
		return lines.join('\n');
	}

	orderedGroups.forEach((group) => {
		lines.push(`## ${group}`);
		lines.push('');
		grouped[group]
			.sort((a, b) => a.title.localeCompare(b.title))
			.forEach((recipe) => {
				lines.push(`- [${recipe.title}](${recipe.uri})`);
				if (recipe.summary) {
					lines.push(`  - ${recipe.summary}`);
				}
			});
		lines.push('');
	});

	return lines.join('\n');
}

function main() {
	const args = parseArgs();
	const repoRoot = process.cwd();
	const pluginSlug = args.plugin;

	if (!pluginSlug) {
		console.error('Error: --plugin is required');
		console.error('Usage: node scripts/recipes/generate-recipe-docs.js --plugin=wp-graphql');
		process.exit(1);
	}

	const configPath = args.config
		? path.resolve(repoRoot, args.config)
		: path.resolve(repoRoot, 'scripts/hooks/plugin-config.json');
	const pluginConfigMap = readJson(configPath);
	const pluginConfig = pluginConfigMap[pluginSlug];

	if (!pluginConfig) {
		console.error(`Error: Plugin "${pluginSlug}" not found in ${configPath}`);
		process.exit(1);
	}

	const docsDir = path.resolve(repoRoot, pluginConfig.docsDir);
	const generatedDir = path.join(docsDir, 'generated');
	const recipesDir = path.join(docsDir, 'recipes');
	const websiteGeneratedDir = path.resolve(repoRoot, 'websites/wpgraphql.com/src/generated');
	const validateOnly = args['validate-only'] === 'true' || args['validate-only'] === true;

	const relations = loadRecipeRelations(docsDir);
	const recipesIndexMarkdown = renderRecipesIndex(relations.recipes);
	const recipesIndexPayload = {
		plugin: pluginSlug,
		generatedAt: new Date().toISOString(),
		stats: {
			totalRecipes: relations.recipes.length,
		},
		recipes: relations.recipes,
		relations: {
			actions: relations.byAction,
			filters: relations.byFilter,
			functions: relations.byFunction,
			byUri: relations.byUri,
		},
	};

	const filesToWrite = [
		{
			path: path.join(recipesDir, 'index.md'),
			content: recipesIndexMarkdown,
		},
		{
			path: path.join(generatedDir, 'recipes-index.json'),
			content: `${JSON.stringify(recipesIndexPayload, null, 2)}\n`,
		},
		{
			path: path.join(websiteGeneratedDir, 'recipes-index.json'),
			content: `${JSON.stringify(recipesIndexPayload, null, 2)}\n`,
		},
	];

	if (validateOnly) {
		const changedFiles = filesToWrite
			.filter((file) => fs.existsSync(file.path))
			.filter((file) => fs.readFileSync(file.path, 'utf8') !== file.content)
			.map((file) => path.relative(process.cwd(), file.path));

		const missingFiles = filesToWrite
			.filter((file) => !fs.existsSync(file.path))
			.map((file) => path.relative(process.cwd(), file.path));

		if (changedFiles.length > 0 || missingFiles.length > 0) {
			throw new Error(
				`Generated recipe docs are stale. Re-run recipe docs generator.\nChanged files:\n${changedFiles
					.map((item) => `- ${item}`)
					.join('\n')}\nMissing files:\n${missingFiles.map((item) => `- ${item}`).join('\n')}`
			);
		}

		return;
	}

	ensureDir(generatedDir);
	ensureDir(recipesDir);
	ensureDir(websiteGeneratedDir);

	filesToWrite.forEach((file) => {
		fs.writeFileSync(file.path, file.content, 'utf8');
	});

	console.log(`Generated recipe docs index for ${pluginSlug}: ${relations.recipes.length} recipes`);
}

if (require.main === module) {
	main();
}
